member.example:
Bind the AudioSource spread property using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceSpreadBinder _spread;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _spread;
    }


Bind the AudioSource spread property by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private AudioSource _audioSource;
        
        private AudioSourceSpreadBinder Spread =>
            new(_audioSource);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public float _spread;
    }

Switch the AudioSource spread between two values using a serialized binder field — the target AudioSource is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private AudioSourceSpreadSwitcherBinder _isHighSpread;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighSpread;
    }


Switch the AudioSource spread between two values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] 
        private AudioSource _audioSource;
        
        [SerializeField]
        private float _highSpread;
        
        [SerializeField]
        private float _lowSpread;
        
        private AudioSourceSpreadSwitcherBinder IsHighSpread => new(
            _audioSource, _highSpread, _lowSpread);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isHighSpread;
    }
